export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult<RowType extends Record<string, unknown> = Record<string, unknown>> {
  rows: RowType[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: RowType) => boolean): RowType[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, RowType[]>;
}

const DEFAULT_DELIMITER = ",";
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = "\n";

const NUMBER_PATTERN = /^[+-]?\d+(\.\d+)?$/;

const coerceValue = (value: string | null): unknown => {
  if (value === null) {
    return null;
  }

  if (value === "") {
    return null;
  }

  const lower = value.toLowerCase();
  if (lower === "null") {
    return null;
  }

  if (lower === "true") {
    return true;
  }

  if (lower === "false") {
    return false;
  }

  if (NUMBER_PATTERN.test(value)) {
    return Number(value);
  }

  return value;
};

const buildResult = <RowType extends Record<string, unknown>>(
  rows: RowType[],
  headers: string[],
  errors: CSVError[]
): CSVResult<RowType> => {
  return {
    rows,
    headers,
    errors,
    filter: (predicate) => rows.filter(predicate),
    sum: (column) => {
      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          total += value;
        }
      }
      return total;
    },
    average: (column) => {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count: () => rows.length,
    groupBy: (column) => {
      const groups = new Map<unknown, RowType[]>();
      for (const row of rows) {
        const key = row[column];
        const existing = groups.get(key);
        if (existing) {
          existing.push(row);
        } else {
          groups.set(key, [row]);
        }
      }
      return groups;
    }
  };
};

export const parseCSV = (input: string, options: CSVOptions = {}): CSVResult => {
  const delimiter = options.delimiter ?? DEFAULT_DELIMITER;
  const quote = options.quote ?? DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator ?? DEFAULT_LINE_SEPARATOR;

  const errors: CSVError[] = [];
  const rawRows: string[][] = [];

  if (input.length === 0) {
    return buildResult([], [], errors);
  }

  let currentRow: string[] = [];
  let currentField = "";
  let inQuotes = false;
  let index = 0;

  while (index < input.length) {
    const char = input[index];

    if (inQuotes) {
      if (char === quote) {
        const nextChar = input[index + 1];
        if (nextChar === quote) {
          currentField += quote;
          index += 2;
          continue;
        }
        inQuotes = false;
        index += 1;
        continue;
      }

      currentField += char;
      index += 1;
      continue;
    }

    if (lineSeparator.length > 0 && input.startsWith(lineSeparator, index)) {
      currentRow.push(currentField);
      rawRows.push(currentRow);
      currentRow = [];
      currentField = "";
      index += lineSeparator.length;
      continue;
    }

    if (char === delimiter) {
      currentRow.push(currentField);
      currentField = "";
      index += 1;
      continue;
    }

    if (char === quote) {
      inQuotes = true;
      index += 1;
      continue;
    }

    currentField += char;
    index += 1;
  }

  if (inQuotes) {
    errors.push({
      row: rawRows.length + 1,
      message: "Unclosed quote detected"
    });
  }

  const shouldPushFinalRow =
    currentRow.length > 0 ||
    currentField.length > 0 ||
    (input.length > 0 && !input.endsWith(lineSeparator));

  if (shouldPushFinalRow) {
    currentRow.push(currentField);
    rawRows.push(currentRow);
  }

  if (rawRows.length === 0) {
    return buildResult([], [], errors);
  }

  const headers = rawRows.shift() ?? [];

  const rows = rawRows.map((row, rowIndex) => {
    if (row.length !== headers.length) {
      errors.push({
        row: rowIndex + 2,
        message: `Row has ${row.length} columns but expected ${headers.length}`
      });
    }

    const record: Record<string, unknown> = {};

    headers.forEach((header, headerIndex) => {
      const rawValue = headerIndex < row.length ? row[headerIndex] : null;
      record[header] = coerceValue(rawValue);
    });

    return record;
  });

  return buildResult(rows, headers, errors);
};

import { parseCSV } from "./csv-parser";

const assert = (condition: boolean, message: string) => {
  if (!condition) {
    throw new Error(message);
  }
};

const assertEqual = (actual: unknown, expected: unknown, message: string) => {
  if (actual !== expected) {
    throw new Error(`${message}. Expected ${String(expected)} but got ${String(actual)}`);
  }
};

const runTests = () => {
  {
    const result = parseCSV("name,age\nAlice,30\nBob,25");
    assertEqual(result.headers.length, 2, "basic parsing headers length");
    assertEqual(result.rows.length, 2, "basic parsing row count");
    assertEqual(result.rows[0].name, "Alice", "basic parsing first name");
    assertEqual(result.rows[0].age, 30, "basic parsing first age coercion");
    assertEqual(result.rows[1].age, 25, "basic parsing second age coercion");
    assertEqual(result.errors.length, 0, "basic parsing errors length");
  }

  {
    const result = parseCSV("name,notes\nAlice,\"hello, world\"\nBob,\"a,b,c\"");
    assertEqual(result.rows[0].notes, "hello, world", "quoted field with comma");
    assertEqual(result.rows[1].notes, "a,b,c", "quoted field with multiple commas");
  }

  {
    const result = parseCSV("name,quote\nAlice,\"He said \"\"hi\"\"\"");
    assertEqual(result.rows[0].quote, "He said \"hi\"", "escaped quote handling");
  }

  {
    const input = "name;note|Alice;'hi;there'|Bob;'ok'";
    const result = parseCSV(input, {
      delimiter: ";",
      quote: "'",
      lineSeparator: "|"
    });
    assertEqual(result.rows.length, 2, "custom delimiter row count");
    assertEqual(result.rows[0].note, "hi;there", "custom quote handling");
  }

  {
    const input = "n,b,t,f,empty,nullable,upper,str\n1,2.5,TRUE,false,,null,NULL,hello";
    const result = parseCSV(input);
    const row = result.rows[0];
    assertEqual(row.n, 1, "type coercion integer");
    assertEqual(row.b, 2.5, "type coercion float");
    assertEqual(row.t, true, "type coercion true");
    assertEqual(row.f, false, "type coercion false");
    assertEqual(row.empty, null, "type coercion empty to null");
    assertEqual(row.nullable, null, "type coercion null literal");
    assertEqual(row.upper, null, "type coercion uppercase null");
    assertEqual(row.str, "hello", "type coercion string");
  }

  {
    const input = "a,b\n1\n2,3,4\n\"unclosed,5";
    const result = parseCSV(input);
    assertEqual(result.errors.length, 3, "malformed row error count");
    assert(result.errors[0].row === 2, "malformed row missing column row number");
    assert(result.errors[1].row === 3, "malformed row extra column row number");
    assert(result.errors[2].row === 4, "malformed row unclosed quote row number");
    assert(
      result.errors[2].message.toLowerCase().includes("unclosed"),
      "malformed row unclosed quote message"
    );
  }

  {
    const result = parseCSV("name,age\nAlice,30\nBob,25\nCharlie,35");
    const filtered = result.filter((row) => (row.age as number) > 30);
    assertEqual(filtered.length, 1, "filter returns matching rows");
    assertEqual(filtered[0].name, "Charlie", "filter returns correct row");
  }

  {
    const result = parseCSV("name,age\nAlice,30\nBob,25\nCharlie,35");
    assertEqual(result.sum("age"), 90, "sum aggregation");
    assertEqual(result.average("age"), 30, "average aggregation");
    assertEqual(result.count(), 3, "count aggregation");
    const grouped = result.groupBy("age");
    assertEqual(grouped.size, 3, "groupBy size");
    assertEqual(grouped.get(30)?.[0].name, "Alice", "groupBy content");
  }

  {
    const result = parseCSV("");
    assertEqual(result.headers.length, 0, "empty input headers length");
    assertEqual(result.rows.length, 0, "empty input rows length");
    assertEqual(result.errors.length, 0, "empty input errors length");
  }

  {
    const result = parseCSV("col\n1\n2");
    assertEqual(result.headers[0], "col", "single column header");
    assertEqual(result.rows.length, 2, "single column row count");
    assertEqual(result.rows[1].col, 2, "single column value");
  }

  {
    const result = parseCSV("a,b");
    assertEqual(result.headers.length, 2, "single row headers length");
    assertEqual(result.rows.length, 0, "single row no data rows");
  }

  {
    const largeField = "x".repeat(10000);
    const input = `col\n"${largeField}"`;
    const result = parseCSV(input);
    assertEqual(result.rows[0].col, largeField, "large field parsing");
  }
};

runTests();
console.log("All tests passed.");

